{"file_path":"/workspace/templates/agents.html","content":"{% extends "base.html" %}

{% block content %}
<div class="p-4 md:p-6">
    <!-- Header -->
    <div class="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 mb-6">
        <div>
            <h2 class="text-2xl font-bold text-gray-800">Agents</h2>
            <p class="text-sm text-gray-500 mt-1">Manage AI agents with custom prompts, tools, and channels</p>
        </div>
        <button onclick="showCreateModal()"
                class="px-4 py-2 bg-indigo-500 hover:bg-indigo-600 text-white rounded-lg text-sm font-medium transition-colors flex items-center gap-2">
            <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 4v16m8-8H4"/></svg>
            New Agent
        </button>
    </div>

    <!-- Agents Grid -->
    <div id="agents-grid" class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        <!-- Populated by JS -->
    </div>

    <div id="agents-empty" class="hidden text-center py-16 text-gray-400">
        <svg class="w-16 h-16 mx-auto mb-4 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z"/></svg>
        <p class="text-lg font-medium">No agents yet</p>
        <p class="text-sm mt-1">Create your first agent to get started.</p>
    </div>
</div>

<!-- Create Agent Modal -->
<div id="create-modal" class="hidden fixed inset-0 z-50 flex items-center justify-center">
    <div class="absolute inset-0 bg-black/50" onclick="closeCreateModal()"></div>
    <div class="relative bg-white rounded-xl w-[90%] max-w-[450px] shadow-xl">
        <div class="p-6">
            <h3 class="text-lg font-semibold text-gray-900 mb-4">New Agent</h3>
            <div class="mb-4">
                <label class="block mb-1 text-gray-700 text-sm font-medium">Agent ID *</label>
                <input type="text" id="new-agent-id" placeholder="e.g., customer_service" class="w-full p-2.5 border border-gray-300 rounded-md text-sm focus:border-indigo-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/10">
                <p class="text-xs text-gray-400 mt-1">Alphanumeric and underscores only</p>
            </div>
            <div class="mb-4">
                <label class="block mb-1 text-gray-700 text-sm font-medium">Name *</label>
                <input type="text" id="new-agent-name" placeholder="e.g., Customer Service" class="w-full p-2.5 border border-gray-300 rounded-md text-sm focus:border-indigo-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/10">
            </div>
            <div class="mb-4">
                <label class="block mb-1 text-gray-700 text-sm font-medium">Description</label>
                <textarea id="new-agent-desc" rows="2" placeholder="Short description" class="w-full p-2.5 border border-gray-300 rounded-md text-sm focus:border-indigo-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/10"></textarea>
            </div>
        </div>
        <div class="flex gap-3 justify-end px-6 pb-5">
            <button onclick="closeCreateModal()" class="px-4 py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors">Cancel</button>
            <button onclick="createAgent()" class="px-4 py-2 bg-indigo-500 hover:bg-indigo-600 text-white rounded-md text-sm font-medium transition-colors">Create</button>
        </div>
    </div>
</div>

<script>
let agents = [];

async function loadAgents() {
    const res = await fetch('/api/agents');
    const data = await res.json();
    agents = data.agents || [];
    renderAgents();
}

function renderAgents() {
    const grid = document.getElementById('agents-grid');
    const empty = document.getElementById('agents-empty');
    if (agents.length === 0) {
        grid.innerHTML = '';
        empty.classList.remove('hidden');
        return;
    }
    empty.classList.add('hidden');

    // Pin super agent to top
    const sorted = [...agents].sort((a, b) => {
        if (a.is_super && !b.is_super) return -1;
        if (!a.is_super && b.is_super) return 1;
        return (a.name || a.id).localeCompare(b.name || b.id);
    });

    grid.innerHTML = sorted.map(a => {
        const enabled = a.enabled !== false && a.enabled !== 0;
        const superBadge = a.is_super
            ? `<span class="text-xs bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded font-semibold ml-1">&#9733; Super</span>`
            : '';
        const toggleSwitch = a.is_super
            ? ''
            : `<label class="relative inline-flex items-center cursor-pointer ml-3 flex-shrink-0">
                    <input type="checkbox" class="sr-only peer" ${enabled ? 'checked' : ''}
                           onchange="toggleAgent('${a.id}', this.checked)">
                    <div class="w-9 h-5 bg-gray-200 peer-focus:ring-2 peer-focus:ring-indigo-300 rounded-full peer peer-checked:bg-indigo-500 after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:after:translate-x-full"></div>
                </label>`;
        const statusBadge = enabled
            ? `<span class="inline-flex items-center gap-1 text-xs font-medium text-green-600 bg-green-50 px-2 py-1 rounded-full">
                    <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
                    Active
               </span>`
            : `<span class="inline-flex items-center gap-1 text-xs font-medium text-gray-500 bg-gray-100 px-2 py-1 rounded-full">
                    <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l-2 2m7-7a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
                    Disabled
               </span>`;
        const deleteBtn = a.is_super
            ? ''
            : `<button onclick="deleteAgent('${a.id}', '${esc(a.name || a.id)}')"
                    class="text-xs text-red-500 hover:text-red-700 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                    Delete
               </button>`;
        return `
        <div class="bg-white rounded-xl shadow-sm border border-gray-100 hover:shadow-md transition-shadow overflow-hidden">
            <div class="p-5">
                <div class="flex justify-between items-start mb-3">
                    <div class="flex-1 min-w-0 cursor-pointer" onclick="window.location.href='/agents/${a.id}'">
                        <h3 class="font-semibold text-gray-800 truncate">${esc(a.name || a.id)}${superBadge}</h3>
                        <p class="text-xs text-gray-400 mt-0.5">ID: ${esc(a.id)}</p>
                    </div>
                    ${toggleSwitch}
                </div>
                <p class="text-sm text-gray-500 line-clamp-2 mb-3">${esc(a.description || 'No description')}</p>
                <div class="flex justify-between items-center">
                    ${statusBadge}
                    ${deleteBtn}
                </div>
            </div>
        </div>`;
    }).join('');
}

function showCreateModal() {
    document.getElementById('create-modal').classList.remove('hidden');
    document.getElementById('new-agent-id').value = '';
    document.getElementById('new-agent-name').value = '';
    document.getElementById('new-agent-desc').value = '';
    document.getElementById('new-agent-id').focus();
}

function closeCreateModal() {
    document.getElementById('create-modal').classList.add('hidden');
}

async function createAgent() {
    const id = document.getElementById('new-agent-id').value.trim();
    const name = document.getElementById('new-agent-name').value.trim();
    const description = document.getElementById('new-agent-desc').value.trim();
    if (!id || !name) return alert('ID and Name are required.');
    if (!/^[a-zA-Z0-9_]+$/.test(id)) return alert('ID must be alphanumeric with underscores only.');

    const res = await fetch('/api/agents', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({id, name, description})
    });
    const data = await res.json();
    if (data.error) return alert(data.error);
    closeCreateModal();
    window.location.href = `/agents/${id}`;
}

async function toggleAgent(agentId, enabled) {
    const res = await fetch(`/api/agents/${agentId}`, {
        method: 'PUT',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({enabled})
    });
    if (!res.ok) {
        const err = await res.json();
        alert(err.error || 'Failed to toggle agent');
        loadAgents();
    }
}

async function deleteAgent(agentId, name) {
    const confirmed = await showConfirm({
        title: `Delete "${name}"?`,
        message: 'This will delete the agent and remove all its files. This cannot be undone.',
        confirmText: 'Delete',
        danger: true
    });
    if (!confirmed) return;

    const res = await fetch(`/api/agents/${agentId}`, {method: 'DELETE'});
    if (!res.ok) {
        const err = await res.json();
        alert(err.error || 'Failed to delete agent');
    }
    loadAgents();
}

function esc(s) {
    const d = document.createElement('div');
    d.textContent = s || '';
    return d.innerHTML;
}

loadAgents();
</script>
{% endblock %}
"}

